<template>
  <div>
    <!-- <div :class="isFixed ? 'is_fixed' : 'nav'"> -->
    <div class="nav">
      <el-tabs
        v-model="activeName"
        @tab-click="handleClick"
        style="backgroud:#000080"
      >
        <el-tab-pane label="Home" name="Home"></el-tab-pane>
        <el-tab-pane label="Research" name="Research"></el-tab-pane>
        <el-tab-pane label="Teaching" name="Teaching"></el-tab-pane>
        <el-tab-pane label="Education" name="Education"></el-tab-pane>
        <el-tab-pane label="CV [PDF]" name="CV"></el-tab-pane>
      </el-tabs>
    </div>
    <!-- <div><MinNav></MinNav></div> -->
    <div style="margin-top: 100px">
      <div id="Home"><home></home></div>
    </div>
    <div>
      <div id="Research"><research></research></div>
    </div>
    <div>
      <div id="Teaching"><teaching></teaching></div>
    </div>
    <div>
      <div id="Education"><education></education></div>
    </div>
    <!-- <div id="third">
      <test></test>
    </div> -->
  </div>
</template>

<script>
import test from "./a.vue";
import home from "./home.vue";
import research from "./research.vue";
import teaching from "./teaching.vue";
import education from "./education.vue";
import MinNav from "@/components/MinNav.vue";
export default {
  name: "homePage",
  components: { test, home, research, teaching, education, MinNav },
  data() {
    return {
      msg: "Welcome to Your Vue.js App",
      activeName: "second"

      // isFixed: false
    };
  },
  mounted() {
    window.addEventListener("scroll", this.initHeight);
  },
  methods: {
    // 切换tabs
    handleClick: function(tab, event) {
      var el = document.querySelector(`#${tab.name}`);
      console.log("tab", el.offsetTop);
      window.scroll({
        top: el.offsetTop - 60,
        behavior: "smooth" // 平滑过渡 --legacy-peer-deps
      });
    }
    // initHeight() {
    //   let scrollTop =
    //     window.pageYOffset ||
    //     document.documentElement.scrollTop ||
    //     document.body.scrollTop;
    //   this.isFixed = scrollTop > 310 ? true : false;
    // }
  }
  // destroyed() {
  //   window.removeEventListener("scroll", this.initHeight, false);
  // }
};
</script>
<style scoped lang="less">
@import "../assets/style/index.less";
</style>
<style scoped lang="css">
.nav {
  position: fixed;
  width: 100%;
  left: 0;
  top: 0;
  z-index: 999;
}
/* .is_fixed {
  position: fixed;
  top: 0;
  width: 100%;
  left: 0;
  z-index: 999;
} */
</style>



